  1	import {
  2	  Button,
  3	  Card,
  4	  CardBody,
  5	  Flex,
  6	  Grid,
  7	  PageSection,
  8	  Title,
  9	  Tooltip,
 10	} from '@patternfly/react-core';
 11	import { SyncAltIcon } from '@patternfly/react-icons';
 12	import React from 'react';
 13	import { useTranslation } from 'react-i18next';
 14	import { useParams } from 'react-router-dom-v5-compat';
 15	import { availablePodAttributes, filtersFromQuery, queryFromFilters } from '../attribute-filters';
 16	import { CenteredContainer } from '../components/centered-container';
 17	import { Filters } from '../components/filters/filter.types';
 18	import { LogsHistogram } from '../components/logs-histogram';
 19	import { LogsMetrics } from '../components/logs-metrics';
 20	import { LogsTable } from '../components/logs-table';
 21	import { LogsToolbar } from '../components/logs-toolbar';
 22	import { RefreshIntervalDropdown } from '../components/refresh-interval-dropdown';
 23	import { TimeRangeDropdown } from '../components/time-range-dropdown';
 24	import { ToggleHistogramButton } from '../components/toggle-histogram-button';
 25	import { downloadCSV } from '../download-csv';
 26	import { LogsConfigProvider, useLogsConfig } from '../hooks/LogsConfigProvider';
 27	import { useLogs } from '../hooks/useLogs';
 28	import { useURLState } from '../hooks/useURLState';
 29	import { Direction, isMatrixResult, Schema } from '../logs.types';
 30	import { getStreamLabelsFromSchema, ResourceLabel } from '../parse-resources';
 31	import { TestIds } from '../test-ids';
 32	import { getInitialTenantFromNamespace } from '../value-utils';
 33	import { TimezoneDropdown } from '../components/timezone-dropdown';
 34	
 35	/*
 36	This comment creates an entry in the translations catalogue for console extensions
 37	
 38	t('plugin__logging-view-plugin~Aggregated Logs')
 39	
 40	*/
 41	
 42	interface LogsDetailPageProps {
 43	  ns?: string;
 44	  name?: string;
 45	}
 46	
 47	const LogsDetailPage: React.FC<LogsDetailPageProps> = ({
 48	  ns: namespaceFromProps,
 49	  name: podNameFromProps,
 50	}) => {
 51	  const { t } = useTranslation('plugin__logging-view-plugin');
 52	
 53	  const { name: podnameFromParams, ns: namespaceFromParams } =
 54	    useParams<{ name: string; ns: string }>();
 55	  const namespace = namespaceFromParams || namespaceFromProps;
 56	  const podname = podnameFromParams || podNameFromProps;
 57	  const [isHistogramVisible, setIsHistogramVisible] = React.useState(false);
 58	
 59	  const { config, configLoaded } = useLogsConfig();
 60	
 61	  const {
 62	    isLoadingLogsData,
 63	    isLoadingMoreLogsData,
 64	    isStreaming,
 65	    logsData,
 66	    logsError,
 67	    getLogs,
 68	    getMoreLogs,
 69	    hasMoreLogsData,
 70	    toggleStreaming,
 71	    getVolume,
 72	    volumeData,
 73	    isLoadingVolumeData,
 74	    volumeError,
 75	    showVolumeGraph,
 76	    getHistogram,
 77	    histogramData,
 78	    isLoadingHistogramData,
 79	    histogramError,
 80	  } = useLogs();
 81	
 82	  const {
 83	    initialQuery,
 84	    query,
 85	    setQueryInURL,
 86	    schema,
 87	    setSchemaInURL,
 88	    areResourcesShown,
 89	    setShowResourcesInURL,
 90	    areStatsShown,
 91	    setShowStatsInURL,
 92	    filters,
 93	    setFilters,
 94	    setTimeRangeInURL,
 95	    interval,
 96	    timeRange,
 97	    direction,
 98	    setDirectionInURL,
 99	    timezone,
100	    setTimezoneInURL,
101	    attributes,
102	  } = useURLState({
103	    getDefaultQuery: ({ schema: s }) => {
104	      const labelMatchers = getStreamLabelsFromSchema(s);
105	      const podLabel = labelMatchers[ResourceLabel.Pod];
106	
107	      return `{ ${podLabel} = "${podname}" }${s == Schema.viaq ? ' | json' : ''}`;
108	    },
109	    getAttributes: ({ config: c, schema: s }) => {
110	      if (namespace && podname) {
111	        return availablePodAttributes(namespace, podname, c, s);
112	      }
113	    },
114	    attributesDependencies: [namespace, podname],
115	  });
116	
117	  const initialTenant = getInitialTenantFromNamespace(namespace);
118	  const tenant = React.useRef(initialTenant);
119	
120	  const handleToggleStreaming = () => {
121	    toggleStreaming({ query, schema });
122	  };
123	
124	  const handleLoadMoreData = (lastTimestamp: number) => {
125	    if (!isLoadingMoreLogsData) {
126	      getMoreLogs({ lastTimestamp, query, namespace, direction, schema });
127	    }
128	  };
129	
130	  const handleSortByDate = (directionValue?: Direction) => {
131	    setDirectionInURL(directionValue);
132	  };
133	
134	  const runQuery = () => {
135	    getLogs({ query, tenant: tenant.current, namespace, timeRange, direction, schema });
136	
137	    if (isHistogramVisible) {
138	      getHistogram({ query, tenant: tenant.current, namespace, timeRange, schema });
139	    }
140	  };
141	
142	  const runVolume = () => {
143	    getVolume({ query, tenant: tenant.current, namespace, timeRange, schema });
144	  };
145	
146	  const handleFiltersChange = (selectedFilters?: Filters) => {
147	    setFilters(selectedFilters);
148	
149	    if (!selectedFilters || Object.keys(selectedFilters).length === 0) {
150	      setQueryInURL(initialQuery);
151	    } else {
152	      const updatedQuery = queryFromFilters({
153	        existingQuery: query,
154	        filters: selectedFilters,
155	        attributes,
156	        schema,
157	      });
158	      setQueryInURL(updatedQuery);
159	    }
160	  };
161	
162	  const handleQueryChange = (queryFromInput: string) => {
163	    setQueryInURL(queryFromInput);
164	
165	    const updatedFilters = filtersFromQuery({
166	      query: queryFromInput,
167	      attributes,
168	      schema,
169	    });
170	
171	    setFilters(updatedFilters);
172	  };
173	
174	  React.useEffect(() => {
175	    if (!configLoaded) {
176	      return;
177	    }
178	
179	    runQuery();
180	  }, [timeRange, isHistogramVisible, direction, configLoaded]);
181	
182	  const isQueryEmpty = query === '';
183	
184	  const resultIsMetric = isMatrixResult(logsData?.data);
185	
186	  React.useEffect(() => {
187	    if (resultIsMetric) {
188	      setIsHistogramVisible(false);
189	    }
190	  }, [resultIsMetric]);
191	
192	  return (
193	    <PageSection>
194	      <Grid hasGutter>
195	        <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
196	          <Title headingLevel="h1" size="lg">
197	            {t('Logs')}
198	          </Title>
199	          <Flex>
200	            <ToggleHistogramButton
201	              isToggled={isHistogramVisible}
202	              onToggle={() => setIsHistogramVisible(!isHistogramVisible)}
203	              data-test={TestIds.ToggleHistogramButton}
204	              isDisabled={resultIsMetric}
205	            />
206	            <TimeRangeDropdown
207	              value={timeRange}
208	              onChange={setTimeRangeInURL}
209	              isDisabled={isQueryEmpty}
210	              timezone={timezone}
211	            />
212	            {config.showTimezoneSelector && (
213	              <TimezoneDropdown
214	                value={timezone}
215	                onChange={setTimezoneInURL}
216	                isDisabled={isQueryEmpty}
217	              />
218	            )}
219	            <RefreshIntervalDropdown onRefresh={runQuery} isDisabled={isQueryEmpty} />
220	            <Tooltip content={<div>Refresh</div>}>
221	              <Button
222	                onClick={runQuery}
223	                aria-label="Refresh"
224	                variant="secondary"
225	                data-test={TestIds.SyncButton}
226	              >
227	                <SyncAltIcon />
228	              </Button>
229	            </Tooltip>
230	          </Flex>
231	        </Flex>
232	
233	        {isHistogramVisible && !resultIsMetric && (
234	          <LogsHistogram
235	            histogramData={histogramData}
236	            timeRange={timeRange}
237	            interval={interval}
238	            isLoading={isLoadingHistogramData}
239	            error={histogramError}
240	            onChangeTimeRange={setTimeRangeInURL}
241	            timezone={timezone}
242	          />
243	        )}
244	
245	        <LogsToolbar
246	          query={query}
247	          onQueryChange={handleQueryChange}
248	          onQueryRun={runQuery}
249	          onVolumeRun={runVolume}
250	          isStreaming={isStreaming}
251	          onStreamingToggle={handleToggleStreaming}
252	          showResources={areResourcesShown}
253	          onShowResourcesToggle={setShowResourcesInURL}
254	          showStats={areStatsShown}
255	          onShowStatsToggle={setShowStatsInURL}
256	          enableStreaming
257	          enableTenantDropdown={false}
258	          isDisabled={isQueryEmpty}
259	          attributeList={attributes}
260	          filters={filters}
261	          onFiltersChange={handleFiltersChange}
262	          onDownloadCSV={() => downloadCSV(logsData)}
263	          schema={schema}
264	          onSchemaSelect={setSchemaInURL}
265	        />
266	
267	        {isLoadingLogsData ? (
268	          <CenteredContainer>{t('Loading...')}</CenteredContainer>
269	        ) : showVolumeGraph ? (
270	          <Card>
271	            <CardBody>
272	              <LogsMetrics
273	                logsData={volumeData}
274	                timeRange={timeRange}
275	                isLoading={isLoadingVolumeData}
276	                error={volumeError}
277	                height={350}
278	                timezone={timezone}
279	                displayLegendTable
280	              />
281	            </CardBody>
282	          </Card>
283	        ) : resultIsMetric ? (
284	          <Card>
285	            <CardBody>
286	              <LogsMetrics
287	                logsData={logsData}
288	                timeRange={timeRange}
289	                isLoading={isLoadingLogsData}
290	                error={logsError}
291	                height={350}
292	                timezone={timezone}
293	                displayLegendTable
294	              />
295	            </CardBody>
296	          </Card>
297	        ) : (
298	          <LogsTable
299	            logsData={logsData}
300	            isStreaming={isStreaming}
301	            onLoadMore={handleLoadMoreData}
302	            onSortByDate={handleSortByDate}
303	            isLoading={isLoadingLogsData}
304	            isLoadingMore={isLoadingMoreLogsData}
305	            hasMoreLogsData={hasMoreLogsData}
306	            showResources={areResourcesShown}
307	            showStats={areStatsShown}
308	            direction={direction}
309	            error={logsError}
310	            timezone={timezone}
311	            hasNamespaceFilter={true}
312	            schema={schema}
313	          />
314	        )}
315	      </Grid>
316	    </PageSection>
317	  );
318	};
319	
320	const LogsDetailPageWrapper: React.FC<LogsDetailPageProps> = (props) => {
321	  return (
322	    <LogsConfigProvider>
323	      <LogsDetailPage {...props} />
324	    </LogsConfigProvider>
325	  );
326	};
327	
328	export default LogsDetailPageWrapper;

